const rvRaw     = $('GET Resumo Validação').first()?.json;
const rsRaw     = $('GET Resumo Semanal').first()?.json;
const ideiasRaw = $('GET Ideias Em Andamento').first()?.json;

const rvArr  = Array.isArray(rvRaw)  ? rvRaw  : [];
const rsArr  = Array.isArray(rsRaw)  ? rsRaw  : [];
const ideias = Array.isArray(ideiasRaw) ? ideiasRaw : [];

if (ideias.length === 0) {
  return [{ json: { skip: true, motivo: 'Nenhuma ideia Em andamento hoje.' } }];
}

const rv = rvArr[0] || {};
const rs = rsArr[0] || {};

const contextoValidacao = [
  rv.conteudo          ? `ANÁLISE GERAL:\n${rv.conteudo}` : null,
  rv.analise_combinada ? `ANÁLISE COMBINADA:\n${rv.analise_combinada}` : null,
  rv.padroes_aprovados ? `PADRÕES APROVADOS:\n${rv.padroes_aprovados}` : null,
  rv.padroes_rejeitados? `PADRÕES REJEITADOS:\n${rv.padroes_rejeitados}` : null,
  rv.insights          ? `INSIGHTS:\n${rv.insights}` : null,
].filter(Boolean).join('\n\n') || 'Primeira semana — sem histórico ainda.';

const contextoSemanal = [
  rs.conteudo           ? `RESUMO SEMANAL:\n${rs.conteudo}` : null,
  rs.resumo             ? `RESUMO:\n${rs.resumo}` : null,
  rs.temas_relevantes   ? `TEMAS RELEVANTES:\n${rs.temas_relevantes}` : null,
  rs.sugestoes_conteudo ? `SUGESTÕES:\n${rs.sugestoes_conteudo}` : null,
].filter(Boolean).join('\n\n') || 'Sem resumo semanal ainda.';

// ─── Diretrizes por plataforma ───────────────────────────
const diretrizes = {
  LinkedIn: `- Tom: profissional, direto, confiante, B2B
- 1ª linha: gancho forte (máx 2 linhas antes do "ver mais")
- 150 a 280 palavras
- Máx 4 emojis estratégicos
- 5 a 8 hashtags (#autopeças #automotivo #gestão)
- CTA claro no final
- PROIBIDO: "No mundo atual", "Em tempos de transformação", começar com "Hoje quero falar sobre"`,

  Instagram: `- Tom: visual, dinâmico, próximo do público
- 1ª linha: gancho emocional ou pergunta impactante
- 80 a 150 palavras (o texto complementa a imagem/vídeo)
- Emojis moderados (máx 6), usados para ritmo
- 8 a 15 hashtags variados (#autopeças #automotivo #mecânica #carros)
- CTA simples: "Salva esse post", "Marca quem precisa ver isso"
- Se tem_imagem: true → descreva a cena/contexto visual`,

  TikTok: `- Tom: descontraído, rápido, autêntico
- Roteiro de vídeo curto: gancho (0-3s) + desenvolvimento (3-45s) + CTA final
- Máx 150 palavras no texto da legenda
- 5 a 10 hashtags (#autopeças #fyp #mecânica #dica)
- Foco em storytelling ou "dica rápida"
- Se tem_imagem: false → escreva roteiro falado em tópicos`,

  YouTube: `- Tom: educativo, aprofundado, autoridade
- Título clicável + descrição SEO (150 a 300 palavras)
- Estrutura: Introdução (gancho) → Desenvolvimento (3-5 pontos) → CTA (inscreva-se / comente)
- 5 a 10 hashtags relevantes
- Inclua timestamps sugeridos se o formato for tutorial/explicativo`,
};

const getDiretrizes = (plataforma) => {
  const key = Object.keys(diretrizes).find(k => k.toLowerCase() === (plataforma||'').toLowerCase());
  return key ? diretrizes[key] : diretrizes.LinkedIn;
};

// ─── SYSTEM PROMPT ───────────────────────────────────────
const systemPrompt = `Você é um especialista sênior em marketing de conteúdo para o setor de autopeças e distribuição automotiva no Brasil.

Sua missão: criar conteúdo otimizado para cada plataforma — LinkedIn, Instagram, TikTok e YouTube — sempre voltado ao segmento B2B de autopeças.

Cada ideia pode ter uma plataforma diferente. Adapte o tom, tamanho, estrutura e hashtags conforme a plataforma indicada.

RETORNO: SOMENTE array JSON válido. Sem markdown. Sem texto fora do colchete.`;

// ─── USER PROMPT ─────────────────────────────────────────
const ideiasFormatadas = ideias.map(i => {
  const plat = (Array.isArray(i.plataformas) ? i.plataformas[0] : i.plataforma) || 'LinkedIn';
  return {
    id:           i.id,
    assunto_tema: i.assunto_tema,
    plataforma:   plat,
    formato:      i.formato || 'Post',
    observacoes:  i.observacoes || null,
    tem_imagem:   !!i.imagem_url,
    diretrizes:   getDiretrizes(plat),
  };
});

const userPrompt = `CONTEXTO DE VALIDAÇÃO:
───────────────────────────────────────────
${contextoValidacao}

CONTEXTO SEMANAL:
───────────────────────────────────────────
${contextoSemanal}

IDEIAS PARA GERAR (${ideias.length}):
${JSON.stringify(ideiasFormatadas, null, 2)}

Para CADA ideia, gere o conteúdo respeitando a plataforma e as diretrizes indicadas no campo "diretrizes".
Se tem_imagem: true → adapte o texto para complementar uma imagem/vídeo.
Se tem_imagem: false → texto standalone.

Retorne EXATAMENTE:
[
  {
    "ideia_id": <número inteiro>,
    "plataforma": "<plataforma da ideia>",
    "conteudo_gerado": "<conteúdo completo pronto para publicar>",
    "hashtags": "<hashtags separadas por espaço>",
    "tem_imagem": <true ou false>
  }
]`;

return [{
  json: {
    ideias,
    claudeBody: {
      model: 'claude-sonnet-4-6',
      max_tokens: 4096,
      system: systemPrompt,
      messages: [{ role: 'user', content: userPrompt }]
    }
  }
}];

const claudeResp = $input.first().json;
const ideias     = $('Preparar Request Claude').first().json.ideias;

const text = claudeResp.content?.[0]?.text || '';
if (!text) throw new Error('Claude retornou resposta vazia: ' + JSON.stringify(claudeResp.error || claudeResp));

const match = text.match(/\[[\s\S]*\]/);
if (!match) throw new Error('Claude não retornou array JSON. Trecho: ' + text.substring(0, 300));

let posts;
try { posts = JSON.parse(match[0]); }
catch(e) { throw new Error('Falha parse JSON: ' + e.message); }

if (!Array.isArray(posts) || posts.length === 0) throw new Error('Array vazio ou inválido.');

return posts.map(post => {
  const ideia = ideias.find(i => i.id === post.ideia_id || i.id === Number(post.ideia_id));
  return {
    json: {
      ideia_id:        Number(post.ideia_id),
      plataforma:      'LinkedIn',
      conteudo_gerado: post.conteudo_gerado,
      hashtags:        post.hashtags || null,
      url_imagem:      ideia?.imagem_url || null,
      url_video:       null,
      status:          'Em andamento',
    }
  };
});

const record = Array.isArray($json) ? $json[0] : $json;
if (!record) throw new Error('Supabase não retornou registro.');
return [{ json: { ideia_id: record.ideia_id } }];
